package org.example.config;
import org.example.security.*; import org.springframework.context.annotation.*; import org.springframework.security.authentication.*; import org.springframework.security.authentication.dao.DaoAuthenticationProvider; import org.springframework.security.config.annotation.authentication.configuration.AuthenticationConfiguration; import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity; import org.springframework.security.config.annotation.web.builders.HttpSecurity; import org.springframework.security.config.http.SessionCreationPolicy; import org.springframework.security.crypto.bcrypt.BCryptPasswordEncoder; import org.springframework.security.crypto.password.PasswordEncoder; import org.springframework.security.web.SecurityFilterChain; import org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter;
@Configuration @EnableMethodSecurity public class SecurityConfig { private final CustomUserDetailsService service; private final JwtAuthenticationFilter filter; public SecurityConfig(CustomUserDetailsService s, JwtAuthenticationFilter f){this.service=s;this.filter=f;} @Bean PasswordEncoder passwordEncoder(){return new BCryptPasswordEncoder();} @Bean DaoAuthenticationProvider authenticationProvider(){ DaoAuthenticationProvider p=new DaoAuthenticationProvider(); p.setUserDetailsService(service); p.setPasswordEncoder(passwordEncoder()); return p;} @Bean AuthenticationManager authenticationManager(AuthenticationConfiguration c) throws Exception {return c.getAuthenticationManager();} @Bean SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception { http.csrf(csrf->csrf.disable()).authorizeHttpRequests(auth->auth.requestMatchers("/auth/**","/hello","/h2-console/**").permitAll().requestMatchers("/admin/**").hasRole("ADMIN").requestMatchers("/users/**","/notifications/**").hasAnyRole("USER","ADMIN").anyRequest().authenticated()).sessionManagement(s->s.sessionCreationPolicy(SessionCreationPolicy.STATELESS)).authenticationProvider(authenticationProvider()).addFilterBefore(filter, UsernamePasswordAuthenticationFilter.class).formLogin(f->f.disable()).httpBasic(b->{}).headers(h->h.frameOptions(fr->fr.sameOrigin())); return http.build();} }
